    for record in records:
        name = record['Project_Name']
        amount = int(record['Amount'])
        if name in lookup:
            lookup[name] += amount
        else:
            lookup[name] = amount
    return lookup

funding_lookup = build_funding_lookup(funding_records)

# Load civic documents
